const rawItems = $input.all();
const items = rawItems.filter(item => item.json.TaskContent);

if (items.length === 0) {
  return [
    {
      json: {
        message: 'Активных задач нет.',
      },
    },
  ];
}

const lines = items.map(item => {
  const t = item.json;
  const deadline = t.DeadlineAt
    ? new Date(t.DeadlineAt).toLocaleString('ru-RU', { timeZone: 'Europe/Moscow' })
    : 'без дедлайна';
  const tracker = t.Tracker_Key ? ` (Tracker: ${t.Tracker_Key})` : '';
  return `TASK-${t.id}: ${t.TaskContent} (дедлайн: ${deadline})${tracker}`;
});

return [
  {
    json: {
      message: lines.join('\n'),
    },
  },
];
